def paginate(items, page_size):
    if page_size <= 0:
        raise ValueError('page_size must be positive')
    total_pages = len(items) // page_size  # Bug: missing last partial page
    pages = {}
    for page_num in range(1, total_pages + 1):
        start = (page_num - 1) * page_size
        end = start + page_size
        pages[page_num] = items[start:end]
    return pages

