class TreeNode:
    def __init__(self, value, children=None):
        self.value = value
        self.children = children or []

def flatten(node):
    """Return all values in the tree as a flat list (DFS pre-order)."""
    result = [node.value]
    for child in node.children:
        result.extend(flatten(child))  # Bug: no visited tracking
    return result

