import os

def find_duplicates(directory):
    """Find duplicate files in a directory. Returns list of (original, duplicate) pairs."""
    contents = {}
    duplicates = []
    for root, dirs, files in os.walk(directory):
        for fname in files:
            path = os.path.join(root, fname)
            with open(path, 'rb') as f:
                data = f.read()  # Bug: loads entire file into memory
            if data in contents:
                duplicates.append((contents[data], path))
            else:
                contents[data] = path
    return duplicates

