class RecordStore:
    def __init__(self):
        self.records = []

    def add(self, record):
        """Add a record dict to the store."""
        self.records.append(record)

    def search(self, field, value):
        """Find all records where record[field] == value."""
        return [r for r in self.records if r.get(field) == value]

    def count(self, field, value):
        """Count records where record[field] == value."""
        return len(self.search(field, value))

