def fibonacci(n):
    """Compute the nth Fibonacci number (0-indexed)."""
    if n <= 1:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

def batch_fibonacci(numbers):
    """Compute Fibonacci for a list of inputs."""
    return [fibonacci(n) for n in numbers]
